class Solution {
    public int maxSubstrings(String word) {
        int maxLength = 0;
        int count = 0;
        for (int i = 0; i < word.length() - 3; i++) {
            int j = i + 1;
            while (j < word.length() && word.charAt(j) == word.charAt(i)) {
                count++;
                j++;
            }
            maxLength = Math.max(maxLength, count);
        }
        return maxLength;
    }
}
```

